// Morse beacon - an advanced script: functions, maps, arrays and a
// tick-driven state machine (never block, never wait - schedule!).
// The RGB LED flashes the message; BOOT cycles messages.

fn on_start() {
    pin(28).input_pullup();          // BOOT button
    this.msgs = ["SOS", "HELLO", "WIRELAB"];
    this.i = 0;
    this.q = [];                     // queued [on, units] steps
    this.t = 0;
    log("beaconing SOS - press BOOT to change the message");
}

fn on_tick(dt_ms) {
    this.t -= dt_ms;
    if this.t > 0 { return; }
    if this.q.len == 0 {
        this.q = plan(this.msgs[this.i]);
    }
    let step = this.q[0];
    this.q.remove(0);
    if step[0] == 1 {
        rgb(0, 90, 30);
    } else {
        rgb(0, 0, 0);
    }
    this.t = step[1] * 90;           // ms per morse unit
}

fn on_pin(gpio, high) {
    if gpio == 28 && !high {
        this.i = (this.i + 1) % this.msgs.len;
        this.q = [];
        this.t = 0;
        rgb(0, 0, 0);
        log(`message: ${this.msgs[this.i]}`);
    }
}

// Turn a message into [on, duration-units] steps.
// Maps pass by reference in Rhai; arrays make fine little structs.
fn plan(msg) {
    let code = #{
        "A": ".-",   "B": "-...", "E": ".",    "H": "....",
        "I": "..",   "L": ".-..", "O": "---",  "R": ".-.",
        "S": "...",  "W": ".--",
    };
    let q = [];
    for ch in msg.chars() {
        if ch == ' ' {
            q.push([0, 7]);          // word gap
            continue;
        }
        let sym = code[`${ch}`];
        if sym == () { continue; }   // unknown letter: skip
        for m in sym.chars() {
            q.push([1, if m == '.' { 1 } else { 3 }]);
            q.push([0, 1]);          // intra-letter gap
        }
        q.push([0, 3]);              // letter gap
    }
    q.push([0, 12]);                 // message gap, then repeat
    q
}
